// CountTime.tsx - Front-end React 정밀 서버시간 동기화 카운트다운 컴포넌트 일부
export const CountTime = ({ templateDetail }) => {
  const [remainTime, setRemainTime] = useState({ d: 0, h: 0, m: 0, s: 0 });
  const timerRef = useRef<NodeJS.Timeout>();

  useEffect(() => {
    // 1. 디바이스 로컬 조작 시간을 방어하기 위한 API 서버 타임 획득
    fetchServerTime().then((serverTime) => {
      const targetTime = new Date(templateDetail.tmrEndDt).getTime();
      let diff = Math.max(0, targetTime - serverTime);

      timerRef.current = setInterval(() => {
        diff = Math.max(0, diff - 1000);
        if (diff <= 0) {
          clearInterval(timerRef.current);
          // 타임아웃 이벤트 콜백 실행 (기획전 영역 비활성화/노출 제외)
          if (templateDetail.onTimeout) templateDetail.onTimeout();
        }

        const d = Math.floor(diff / (1000 * 60 * 60 * 24));
        const h = Math.floor((diff % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
        const m = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
        const s = Math.floor((diff % (1000 * 60)) / 1000);
        setRemainTime({ d, h, m, s });
      }, 1000);
    });
    return () => clearInterval(timerRef.current);
  }, [templateDetail.tmrEndDt]);

  return (
    <div style={{ backgroundColor: templateDetail.bkgdClr }}>
      <FlipTimer remain={remainTime} title={templateDetail.tmrTitlText} color={templateDetail.tmrClr} />
    </div>
  );
};

