// SearchInput.tsx - Front-end React 검색 인풋 + 추천 키워드 렌더링 핵심 로직
export default function SearchInput({ value, onChange, onSearchSubmit, onKeywordSelect, inputRef, contentRef }) {
  const { data: keywordData } = useFetchEventKeyword({ options: { staleTime: 1000 * 60 * 2 } });

  const handleKeyPress = (e) => {
    if (e.key === 'Enter') { e.preventDefault(); onSearchSubmit(); }
  };

  return (
    <div className={styles.searchArea} ref={contentRef}>
      <div className={styles.searchBox}>
        {/* 언더라인 border-bottom: 2px solid $black 구분선 방식의 입력창 */}
        <input type="text" enterKeyHint="search" ref={inputRef}
          value={value} autoComplete="off"
          placeholder="기획전을 검색해 보세요"
          onChange={(e) => onChange(e.target.value)}
          onKeyPress={handleKeyPress} />
        {/* 입력값이 있을 때만 X 지우기 버튼 표시 */}
        {value !== '' && (
          <button type="button" className={styles.iconDelSearch}
            onClick={() => { onChange(''); inputRef?.current?.focus(); }}>
            <span className="blind">검색어 지우기</span>
          </button>
        )}
        {/* 돋보기 아이콘 버튼 (SVG 이미지 방식) */}
        <button type="button" className={styles.btnSearch}
          onClick={() => onSearchSubmit()}>
          <span className="blind">검색</span>
        </button>
      </div>
      {/* 추천 키워드 영역: API 미등록 시 미노출 */}
      {keywordData?.body?.length > 0 && (
        <div className={styles.keywordList}>
          {keywordData.body.map((kw, i) => (
            <span key={kw.keyword + i} className={styles.keyword}
              onClick={() => onKeywordSelect(kw)}>#{kw.keyword}</span>
          ))}
        </div>
      )}
    </div>
  );
}

