// RouletteGame.tsx - Front-end React 룰렛 회전판 인터랙션 및 애니메이션 제어 로직 일부
const RouletteGame = React.memo(({ rouletteInfo, isPreview }) => {
  const [isSpinning, setIsSpinning] = useState(false);
  const [prizeDeg, setPrizeDeg] = useState(0);
  const { mutate: claimReward } = useMutationExhbRouletClaimPOST({
    onSuccess: (data) => {
      // 1. 당첨 결과에 따른 각도 계산 (전체 360도 중 당첨 구간 타겟팅 + 5회 이상 강제 롤링 보정)
      const targetSector = data.winIndex; // 예: 0 ~ 5 (6칸 기준)
      const sectorDeg = 360 / (rouletteInfo.rouletType === '6' ? 6 : 8);
      const randomOffset = sectorDeg * 0.1 + Math.random() * (sectorDeg * 0.8);
      const stopDeg = 3600 + (360 - (targetSector * sectorDeg + randomOffset));
      setPrizeDeg(stopDeg);
      setIsSpinning(true);

      setTimeout(() => {
        setIsSpinning(false);
        LFAlert.alert(`${data.rewardName}에 당첨되셨습니다! 🎁`);
      }, 5000); // 5초간 회전 애니메이션 진행
    },
    onError: (err) => {
      LFAlert.alert(err.message || "이미 오늘 참여하셨거나 룰렛 참여 대상이 아닙니다.");
    }
  });

  const handleStartSpin = () => {
    if (isPreview) return LFAlert.alert("미리보기 화면에서는 룰렛을 돌릴 수 없습니다.");
    if (isSpinning) return;
    claimReward({ campaignNo: rouletteInfo.rouletCampaignNo });
  };
  // ...
});

