this.fnCheckValidation = function ()
{
	var colorCodePattern = /^#[0-9A-Fa-f]{6,8}$/;
	if(this.editBgColor.value && !colorCodePattern.test(this.editBgColor.value)){
		this.gfnAlert("msg.err.validator", ["배경색상 코드 항목을 체크해주세요."]);
		return false;
	}
	if (this.textTopDesc.value && this.textBottomDesc.value)
	{
		this.gfnAlert("msg.err.validator", ["상단 설명 문구, 하단 설명 문구 중 하나만 입력하세요."]);
		return false;
	}
	var pcImg = this.editPCImg.value;
	var moImg = this.editMOImg.value;
	var isCheckImgFlag = (pcImg != null && pcImg != "") != (moImg != null && moImg != "");
	if(isCheckImgFlag){
		this.gfnAlert("msg.err.validator", ["PC이미지와 MO이미지 모두 입력해주세요."]);
		return false;
	}
	for(var i=1; i<=this.editCouponCount.value; i++){
		var nDiv = this["divBenefit"+i];
		if(!nDiv.form.editCouponID.value){
			this.gfnAlert("msg.err.validator", ["쿠폰을 연결해 주세요."]);
			return false;
		}
	}
	return true;
};
